// TypeScript implementation for Any vs Unknown
interface AnyvsUnknownPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processAnyvsUnknown(item: AnyvsUnknownPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processAnyvsUnknown({ id: 1, title: 'Any vs Unknown', status: 'active' }));

